LIBRARY IEEE;
USE IEEE.STD_LOGIC_1164.ALL;

ENTITY ControlUnit IS
    PORT (
        opcode : IN std_logic_vector(4 DOWNTO 0);

        -- Control Signals
        alu_op : OUT std_logic_vector(3 DOWNTO 0);
        reg_write : OUT std_logic;
        ccr_write : OUT std_logic;
        rsrc1_mux_sel : OUT std_logic; -- 0: Rsrc1, 1: Rdst (for NOT/INC), also used for SP selection

        -- Memory Control Signals
        mem_read : OUT std_logic;
        mem_write : OUT std_logic;
        mem_addr_inc : OUT std_logic; -- Memory address adder control (adds 1 to address)

        -- Stack and Branch Control Signals
        is_push : OUT std_logic; -- PUSH instruction
        is_pushf : OUT std_logic; -- Push Flags instruction (for INT)
        is_pop : OUT std_logic; -- POP instruction
        is_call : OUT std_logic; -- CALL instruction
        is_ret : OUT std_logic; -- RET instruction
        is_int : OUT std_logic; -- INT instruction
        is_rti : OUT std_logic; -- RTI instruction
        is_jmp_int : OUT std_logic; -- JMP to interrupt vector (for INT cycle 3)
        use_sp : OUT std_logic; -- Use Stack Pointer as source

        -- Jump Control Signals
        is_jz : OUT std_logic; -- JZ instruction (Jump if Zero)
        is_jn : OUT std_logic; -- JN instruction (Jump if Negative)
        is_jc : OUT std_logic; -- JC instruction (Jump if Carry)
        is_jmp : OUT std_logic; -- JMP instruction (Unconditional Jump)

        -- PC Control Signals
        pc_write : OUT std_logic; -- Enable PC write
        ifid_flush : OUT std_logic; -- Flush IF/ID register
        pc_mux_sel : OUT std_logic_vector(1 DOWNTO 0); -- 00: PC+1, 01: Imm, 10: Memory data

        -- Injection Control (tells IF what to inject next)
        inject_opcode : OUT std_logic_vector(4 DOWNTO 0); -- Opcode to inject (00000 = no inject)

        -- Special Signals
        io_in : OUT std_logic; -- For IN
        io_out : OUT std_logic; -- For OUT
        halt : OUT std_logic -- For HLT
    );
END ControlUnit;

ARCHITECTURE Behavioral OF ControlUnit IS
    -- ALU Operation Constants (4-bit encoding)
    CONSTANT ALU_NOP : std_logic_vector(3 DOWNTO 0) := "0000";
    CONSTANT ALU_PASS_A : std_logic_vector(3 DOWNTO 0) := "0001";
    CONSTANT ALU_PASS_B : std_logic_vector(3 DOWNTO 0) := "0010";
    CONSTANT ALU_ADD : std_logic_vector(3 DOWNTO 0) := "0011";
    CONSTANT ALU_NOT : std_logic_vector(3 DOWNTO 0) := "0100";
    CONSTANT ALU_INC : std_logic_vector(3 DOWNTO 0) := "0101";
    CONSTANT ALU_DEC : std_logic_vector(3 DOWNTO 0) := "0110";
    CONSTANT ALU_SETC : std_logic_vector(3 DOWNTO 0) := "0111";

    -- PC Mux Select Constants
    CONSTANT PC_MUX_PLUS1 : std_logic_vector(1 DOWNTO 0) := "00";
    CONSTANT PC_MUX_IMM : std_logic_vector(1 DOWNTO 0) := "01";
    CONSTANT PC_MUX_MEM : std_logic_vector(1 DOWNTO 0) := "10";

    -- Internal Opcode Constants for injection
    CONSTANT OP_NOP : std_logic_vector(4 DOWNTO 0) := "00000";
    CONSTANT OP_PUSH_F : std_logic_vector(4 DOWNTO 0) := "01110";
    CONSTANT OP_POP_PC : std_logic_vector(4 DOWNTO 0) := "01111";
    CONSTANT OP_LOAD_PC : std_logic_vector(4 DOWNTO 0) := "11110";
BEGIN
    PROCESS (opcode)
    BEGIN
        -- Defaults
        alu_op <= ALU_NOP;
        reg_write <= '0';
        ccr_write <= '0';
        rsrc1_mux_sel <= '0';
        mem_read <= '0';
        mem_write <= '0';
        mem_addr_inc <= '0';
        is_push <= '0';
        is_pushf <= '0';
        is_pop <= '0';
        is_call <= '0';
        is_ret <= '0';
        is_int <= '0';
        is_rti <= '0';
        is_jmp_int <= '0';
        use_sp <= '0';
        is_jz <= '0';
        is_jn <= '0';
        is_jc <= '0';
        is_jmp <= '0';
        pc_write <= '1'; -- Default: PC writes normally
        ifid_flush <= '0';
        pc_mux_sel <= PC_MUX_PLUS1;
        inject_opcode <= OP_NOP; -- Default: no injection
        io_in <= '0';
        io_out <= '0';
        halt <= '0';

        CASE opcode IS
                -- Zero Operand Instructions
            WHEN "00000" => -- NOP
                NULL;

            WHEN "11111" => -- HLT
                halt <= '1';
                pc_write <= '0'; -- Freeze PC

            WHEN "00010" => -- SETC
                ccr_write <= '1';
                alu_op <= ALU_SETC;

                -- One Operand Instructions
            WHEN "10010" => -- NOT Rdst
                reg_write <= '1';
                alu_op <= ALU_NOT;
                ccr_write <= '1';
                rsrc1_mux_sel <= '1'; -- Select Rdst as source

            WHEN "10011" => -- INC Rdst
                reg_write <= '1';
                alu_op <= ALU_INC;
                ccr_write <= '1';
                rsrc1_mux_sel <= '1'; -- Select Rdst as source

            WHEN "10001" => -- OUT Rdst
                io_out <= '1';

            WHEN "10000" => -- IN Rdst
                reg_write <= '1';
                io_in <= '1';

                -- Karim starts here btw
            WHEN "11100" => -- CALL
                is_call <= '1';
                use_sp <= '1'; -- Read SP from register file
                rsrc1_mux_sel <= '1'; -- Select SP as Rsrc1
                alu_op <= ALU_DEC; -- Decrement SP
                reg_write <= '1'; -- Write decremented SP back
                mem_write <= '1'; -- Write PC+1 to memory
                mem_addr_inc <= '1'; -- Add 1 to memory address (SP-1+1=SP)
                pc_mux_sel <= PC_MUX_IMM; -- PC <- Immediate value
                ifid_flush <= '1'; -- Flush IF/ID register
                pc_write <= '1'; -- Enable PC write

            WHEN "00100" => -- RET
                is_ret <= '1';
                use_sp <= '1'; -- Read SP from register file
                rsrc1_mux_sel <= '1'; -- Select SP as Rsrc1
                alu_op <= ALU_INC; -- Increment SP
                reg_write <= '1'; -- Write incremented SP back
                mem_read <= '1'; -- Read return address from memory
                mem_addr_inc <= '0'; -- No increment on memory address
                pc_mux_sel <= PC_MUX_MEM; -- PC <- Memory data (return address)
                ifid_flush <= '1'; -- Flush IF/ID register
                pc_write <= '1'; -- Enable PC write

            WHEN "11101" => -- INT
                is_int <= '1';
                use_sp <= '1'; -- Read SP from register file
                rsrc1_mux_sel <= '1'; -- Select SP as Rsrc1
                alu_op <= ALU_DEC; -- Decrement SP
                reg_write <= '1'; -- Write decremented SP back
                mem_write <= '1'; -- Write PC+1 to memory
                mem_addr_inc <= '1'; -- Add 1 to memory address
                pc_write <= '0'; -- Disable PC write
                inject_opcode <= OP_PUSH_F; -- Inject PUSH_FLAGS next

            WHEN "01110" => -- Push Flag (INT Cycle 2)
                is_pushf <= '1';
                use_sp <= '1'; -- Read SP from register file
                rsrc1_mux_sel <= '1'; -- Select SP as Rsrc1
                alu_op <= ALU_DEC; -- Decrement SP
                reg_write <= '1'; -- Write decremented SP back
                mem_write <= '1'; -- Write FLAGS to memory
                mem_addr_inc <= '1'; -- Add 1 to memory address
                pc_write <= '0'; -- Disable PC write
                inject_opcode <= OP_LOAD_PC; -- Inject LOAD_PC next
                --jump int
            WHEN "11110" => -- Load PC (INT Cycle 3 / RTI Cycle 3)
                is_jmp_int <= '1';
                alu_op <= ALU_PASS_B; -- Pass immediate/address
                mem_read <= '1'; -- Read new PC from memory
                mem_addr_inc <= '0'; -- No increment
                pc_mux_sel <= PC_MUX_MEM; -- PC <- Memory data
                ifid_flush <= '1'; -- Flush IF/ID & ID/EX
                pc_write <= '1'; -- Enable PC write
                inject_opcode <= OP_NOP; -- No injection, sequence done

            WHEN "00011" => -- RTI (Cycle 1: Pop FLAGS)
                is_rti <= '1';
                use_sp <= '1'; -- Read SP from register file
                rsrc1_mux_sel <= '1'; -- Select SP as Rsrc1
                alu_op <= ALU_INC; -- Increment SP
                reg_write <= '0'; -- Don't write SP yet (done in next cycle)
                mem_read <= '1'; -- Read FLAGS from memory
                mem_addr_inc <= '0'; -- No increment on memory address
                ccr_write <= '1'; -- Write to CCR/FLAGS register
                pc_write <= '0'; -- Disable PC write
                inject_opcode <= OP_POP_PC; -- Inject POP_FLAGS next

            WHEN "01111" => -- Pop PC (RTI Cycle 2: Pop PC)
                use_sp <= '1'; -- Read SP from register file (forwarded SP+1)
                rsrc1_mux_sel <= '1'; -- Select SP as Rsrc1
                alu_op <= ALU_INC; -- Increment SP again (SP+2)
                reg_write <= '1'; -- Write SP back to register file
                mem_read <= '1'; -- Read PC from memory
                mem_addr_inc <= '0'; -- No increment on memory address
                pc_write <= '0'; -- Disable PC write (done in LOAD_PC)
                inject_opcode <= OP_NOP; -- Inject LOAD_PC next

            WHEN "11000" => -- JMP Imm (Executed in Decode stage)
                is_jmp <= '1';
                alu_op <= ALU_NOP;
                reg_write <= '0';
                mem_write <= '0';
                mem_read <= '0';
                pc_mux_sel <= PC_MUX_IMM;
                ifid_flush <= '1';
                pc_write <= '1';

            WHEN "11001" => -- JZ Imm (Executed in Execute stage)
                is_jz <= '1';
                alu_op <= ALU_NOP;
                reg_write <= '0';
                mem_write <= '0';
                mem_read <= '0';
                pc_write <= '1';

            WHEN "11010" => -- JN Imm (Executed in Execute stage)
                is_jn <= '1';
                alu_op <= ALU_NOP;
                reg_write <= '0';
                mem_write <= '0';
                mem_read <= '0';
                pc_write <= '1';

            WHEN "11011" => -- JC Imm (Executed in Execute stage)
                is_jc <= '1';
                alu_op <= ALU_NOP;
                reg_write <= '0';
                mem_write <= '0';
                mem_read <= '0';
                pc_write <= '1';

            WHEN OTHERS =>
                NULL;
        END CASE;
    END PROCESS;
END Behavioral;

