    read_data1 <= registers(to_integer(unsigned(read_reg1)));
    read_data2 <= registers(to_integer(unsigned(read_reg2)));

    -- Sync Write
    process(clk, rst)
    begin
        if rst = '1' then
            registers <= (others => (others => '0'));
