		a : IN std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
		b : IN std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
		op : IN alu_op_t;
		f : OUT std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
		zero_flag : OUT std_logic;
		carry_flag : OUT std_logic;
		negative_flag : OUT std_logic;
		flags_we : OUT std_logic
	);
END ENTITY ALU;

ARCHITECTURE behavioral OF ALU IS
BEGIN
	PROCESS (a, b, op)
		VARIABLE ua, ub : unsigned(DATA_WIDTH - 1 DOWNTO 0);
		VARIABLE wide_res : unsigned(DATA_WIDTH DOWNTO 0);
		VARIABLE carry : std_logic;
		VARIABLE flags_we_var : std_logic;
	BEGIN
		ua := unsigned(a);
		ub := unsigned(b);

		wide_res := (wide_res'RANGE => '0');
		carry := '0';
		flags_we_var := '0';

		CASE op IS
			WHEN NOOP =>
				NULL;

			WHEN PASS_A =>
				wide_res := ('0' & ua);

			WHEN PASS_B =>
				wide_res := ('0' & ub);

			WHEN AND_OP =>
				wide_res := ('0' & (ua AND ub));
				flags_we_var := '1';

			WHEN NOT_OP =>
				wide_res := ('0' & NOT ua);
				flags_we_var := '1';

			WHEN ADD =>
				wide_res := ('0' & ua) + ('0' & ub);
				flags_we_var := '1';

			WHEN SUB =>
				wide_res := ('0' & ua) - ('0' & ub);
				flags_we_var := '1';

			WHEN SETC =>
				-- MSB = 1, all other bits 0
				wide_res := (OTHERS => '0');
				wide_res(DATA_WIDTH) := '1';
				flags_we_var := '1';

			WHEN INC =>
				wide_res := ('0' & ua) + 1;
				flags_we_var := '1';

