        alu_result_in   : in  STD_LOGIC_VECTOR (31 downto 0);
        rd2             : in  STD_LOGIC_VECTOR (31 downto 0);
        pc_in           : in  STD_LOGIC_VECTOR (31 downto 0);
        flags_in        : in  STD_LOGIC_VECTOR (31 downto 0);

        mem_read        : in  STD_LOGIC;
        mem_write       : in  STD_LOGIC;

        is_push         : in  STD_LOGIC;
        is_pushf        : in  STD_LOGIC;
        is_pop          : in  STD_LOGIC;
        is_call         : in  STD_LOGIC;
        is_ret          : in  STD_LOGIC;
        is_int          : in  STD_LOGIC;
        is_rti          : in  STD_LOGIC;
        is_jmp_int      : in  STD_LOGIC;

        int_idx         : in  STD_LOGIC;

        mem_data_out    : out STD_LOGIC_VECTOR (31 downto 0);
        alu_result_out  : out STD_LOGIC_VECTOR (31 downto 0)
    );
end Memory_Stage;

architecture behavioral of Memory_Stage is

    component Memory is
        port (
            clk         : in  STD_LOGIC;
            mem_read    : in  STD_LOGIC;
            mem_write   : in  STD_LOGIC;                       
            address     : in  STD_LOGIC_VECTOR (17 downto 0);
            data_in     : in  STD_LOGIC_VECTOR (31 downto 0);
            data_out    : out STD_LOGIC_VECTOR (31 downto 0)
        );
    end component;

    component SP_Unit is
        port (
            clk         : in  STD_LOGIC;
            rst         : in  STD_LOGIC;
            sp_write_en : in  STD_LOGIC; 
            inc_dec_sel : in  STD_LOGIC;
            sp_out      : out STD_LOGIC_VECTOR (31 downto 0);
            sp_plus_one : out STD_LOGIC_VECTOR (31 downto 0)
        );
    end component;

    signal sp_current          : STD_LOGIC_VECTOR (31 downto 0);
    signal sp_plus_one         : STD_LOGIC_VECTOR (31 downto 0);

    signal mem_addr_in         : STD_LOGIC_VECTOR (17 downto 0);
    signal mem_data_in         : STD_LOGIC_VECTOR (31 downto 0);

    signal sp_write_enable     : STD_LOGIC;
    signal sp_inc_dec          : STD_LOGIC;
    signal is_stack_push       : STD_LOGIC; 
    signal is_stack_pop        : STD_LOGIC;

    signal mem_read_internal   : STD_LOGIC;
    signal mem_write_internal  : STD_LOGIC;

begin
    is_stack_push <= is_push or is_pushf or is_call or is_int;
    is_stack_pop  <= is_pop or is_ret or is_rti;

    -- Address Mux
    process(rst, is_stack_push, is_stack_pop, is_jmp_int, int_idx, sp_current, sp_plus_one, alu_result_in)
    begin
        if rst = '1' then
            mem_addr_in <= (others => '0');

        elsif is_jmp_int = '1' then
            mem_addr_in <= std_logic_vector(to_unsigned(0, 16) & '1' & int_idx);

        elsif is_stack_push = '1' then
            mem_addr_in <= sp_current(17 downto 0);

        elsif is_stack_pop = '1' then
            mem_addr_in <= sp_plus_one(17 downto 0);

        else
            mem_addr_in <= alu_result_in(17 downto 0);
        end if;
    end process;

    -- Data Input Mux
    process(is_call, is_int, is_pushf, pc_in, flags_in, rd2)
    begin
        if is_pushf = '1' then
            mem_data_in <= flags_in;

        elsif is_call = '1' or is_int = '1' then
            mem_data_in <= pc_in; 

        else
            mem_data_in <= rd2;
        end if;
    end process;

    sp_write_enable <= is_stack_push or is_stack_pop;

    -- Pop/Ret/Rti => SP = SP + 1
    -- Push/Pushf/Call/Int => SP = SP - 1
    sp_inc_dec <= is_stack_pop;

    mem_read_internal  <= mem_read when rst = '0' else '1';
    mem_write_internal <= mem_write when rst = '0' else '0';

