        port map (
            clk       => clk,
            mem_read  => mem_read_internal,
            mem_write => mem_write_internal,
            address   => mem_addr_in,
            data_in   => mem_data_in,
            data_out  => mem_data_out
        );

    SP: SP_Unit
        port map (
