library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity SP_Unit is
    port (
        clk         : in  STD_LOGIC;
        rst         : in  STD_LOGIC;
        sp_write_en : in  STD_LOGIC; 
        inc_dec_sel : in  STD_LOGIC; -- '1' for INC, '0' for DEC

        sp_out      : out STD_LOGIC_VECTOR (31 downto 0);
        sp_plus_one : out STD_LOGIC_VECTOR (31 downto 0)
    );
end SP_Unit;

architecture behavioral of SP_Unit is
    signal sp_reg : unsigned(31 downto 0) := x"0003FFFF";
    signal inc_output : unsigned(31 downto 0);
    signal dec_output   : unsigned(31 downto 0);
    signal mux_output  : unsigned(31 downto 0);
    constant RESET_VALUE : unsigned(31 downto 0) := x"0003FFFF";
begin

    inc_output   <= sp_reg + 1;
    dec_output   <= sp_reg - 1;

    sp_out      <= std_logic_vector(sp_reg);
    sp_plus_one <= std_logic_vector(inc_output);

    mux_output <= inc_output when inc_dec_sel = '1' else dec_output;

    process(clk, rst)
    begin
        if rst = '1' then
            sp_reg <= RESET_VALUE;
        elsif rising_edge(clk) then
            if sp_write_en = '1' then
                sp_reg <= mux_output;
            end if;
        end if;
    end process;
end behavioral;

