entity Writeback_TB is
end Writeback_TB;

-- All made by AI lol
architecture Behavioral of Writeback_TB is

    component WritebackStage is
        port (
            alu_result, mem_data, in_port : in STD_LOGIC_VECTOR(31 downto 0);
            mem_to_reg : in STD_LOGIC;
            alu_to_reg : in STD_LOGIC;
            in_port_to_reg : in STD_LOGIC;
            write_data : out STD_LOGIC_VECTOR(31 downto 0)
        );
    end component;

    signal alu_result : STD_LOGIC_VECTOR(31 downto 0) := x"00000000";
    signal mem_data : STD_LOGIC_VECTOR(31 downto 0) := x"00000000";
    signal in_port : STD_LOGIC_VECTOR(31 downto 0) := x"00000000";
    signal mem_to_reg : STD_LOGIC := '0';
    signal alu_to_reg : STD_LOGIC := '0';
    signal in_port_to_reg : STD_LOGIC := '0';
    signal write_data : STD_LOGIC_VECTOR(31 downto 0);

    -- Helper function to convert std_logic_vector to hex string
    function to_hex_string(slv : std_logic_vector(31 downto 0)) return string is
        variable result : string(1 to 8);
        variable nibble : std_logic_vector(3 downto 0);
    begin
        for i in 0 to 7 loop
            nibble := slv(31-i*4 downto 28-i*4);
            case nibble is
                when "0000" => result(i+1) := '0';
                when "0001" => result(i+1) := '1';
                when "0010" => result(i+1) := '2';
                when "0011" => result(i+1) := '3';
                when "0100" => result(i+1) := '4';
                when "0101" => result(i+1) := '5';
                when "0110" => result(i+1) := '6';
                when "0111" => result(i+1) := '7';
                when "1000" => result(i+1) := '8';
                when "1001" => result(i+1) := '9';
                when "1010" => result(i+1) := 'A';
                when "1011" => result(i+1) := 'B';
                when "1100" => result(i+1) := 'C';
                when "1101" => result(i+1) := 'D';
                when "1110" => result(i+1) := 'E';
                when "1111" => result(i+1) := 'F';
                when others => result(i+1) := 'X';
            end case;
        end loop;
        return result;
    end function;

begin

