library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;
use work.alu_pkg.ALL;

entity Processor is
    port (
        clk         : in  STD_LOGIC;
        rst         : in  STD_LOGIC;
        in_port     : in  STD_LOGIC_VECTOR(31 downto 0);
        out_port    : out STD_LOGIC_VECTOR(31 downto 0)
    );
end Processor;

architecture Behavioral of Processor is

    -- =========================================================================
    -- COMPONENT DECLARATIONS
    -- =========================================================================

    component Fetch_Stage is
        port (
            clk                 : in  STD_LOGIC;
            rst                 : in  STD_LOGIC;
            reti_pc_sel         : in  STD_LOGIC;
            reti_pc_value       : in  STD_LOGIC_VECTOR(31 downto 0);
            branch_taken        : in  STD_LOGIC;
            branch_target       : in  STD_LOGIC_VECTOR(31 downto 0);
            jump_req            : in  STD_LOGIC;
            jump_target         : in  STD_LOGIC_VECTOR(31 downto 0);
            stall               : in  STD_LOGIC;
            pc_write_enable     : in  STD_LOGIC;
            force_instr_en      : in  STD_LOGIC;
            force_instr         : in  STD_LOGIC_VECTOR(31 downto 0);
            merge_upper_half    : in  STD_LOGIC_VECTOR(15 downto 0);
            merge_enable        : in  STD_LOGIC;
            flush_fetch         : in  STD_LOGIC;
            instr_mem_data      : in  STD_LOGIC_VECTOR(31 downto 0);
            mem_address         : out STD_LOGIC_VECTOR(17 downto 0);
            mem_read            : out STD_LOGIC;
            pc_current          : out STD_LOGIC_VECTOR(31 downto 0);
            pc_plus_one_out     : out STD_LOGIC_VECTOR(31 downto 0);
            instruction_out     : out STD_LOGIC_VECTOR(31 downto 0);
            instruction_valid   : out STD_LOGIC
        );
    end component;

    component DecodeStage is
        port (
            clk             : in  STD_LOGIC;
            rst             : in  STD_LOGIC;
            instr           : in  STD_LOGIC_VECTOR(31 downto 0);
            write_data      : in  STD_LOGIC_VECTOR(31 downto 0);
            write_reg_addr  : in  STD_LOGIC_VECTOR(2 downto 0);
            reg_write_en    : in  STD_LOGIC;
            read_data1      : out STD_LOGIC_VECTOR(31 downto 0);
            read_data2      : out STD_LOGIC_VECTOR(31 downto 0);
            imm_ext         : out STD_LOGIC_VECTOR(31 downto 0);
            alu_op          : out STD_LOGIC_VECTOR(3 downto 0);
            reg_write       : out STD_LOGIC;
            ccr_write       : out STD_LOGIC;
            mem_read        : out STD_LOGIC;
            mem_write       : out STD_LOGIC;
            mem_addr_inc    : out STD_LOGIC;
            is_pushf        : out STD_LOGIC;
            is_call         : out STD_LOGIC;
            is_ret          : out STD_LOGIC;
            is_int          : out STD_LOGIC;
            is_rti          : out STD_LOGIC;
            is_jmp_int      : out STD_LOGIC;
            use_sp          : out STD_LOGIC;
            pc_write        : out STD_LOGIC;
            ifid_flush      : out STD_LOGIC;
            pc_mux_sel      : out STD_LOGIC_VECTOR(1 downto 0);
            inject_opcode   : out STD_LOGIC_VECTOR(4 downto 0);
            io_in           : out STD_LOGIC;
            io_out          : out STD_LOGIC;
            halt            : out STD_LOGIC
        );
    end component;

    component ExecuteStage is
        generic (
            DATA_WIDTH : integer := 32
        );
        port (
            clk             : in  STD_LOGIC;
            rst             : in  STD_LOGIC;
            jz              : in  STD_LOGIC;
            jn              : in  STD_LOGIC;
            jc              : in  STD_LOGIC;
            alu_op          : in  alu_op_t;
            operand_a       : in  STD_LOGIC_VECTOR(DATA_WIDTH-1 downto 0);
            operand_b       : in  STD_LOGIC_VECTOR(DATA_WIDTH-1 downto 0);
            immediate_value : in  STD_LOGIC_VECTOR(DATA_WIDTH-1 downto 0);
            use_immediate   : in  STD_LOGIC;
            wb_value        : in  STD_LOGIC_VECTOR(DATA_WIDTH-1 downto 0);
            mem_value       : in  STD_LOGIC_VECTOR(DATA_WIDTH-1 downto 0);
            forwarding_a_sel: in  STD_LOGIC_VECTOR(1 downto 0);
            forwarding_b_sel: in  STD_LOGIC_VECTOR(1 downto 0);
            flags_we        : in  STD_LOGIC;
            flags_data      : in  STD_LOGIC_VECTOR(2 downto 0);
            alu_out         : out STD_LOGIC_VECTOR(DATA_WIDTH-1 downto 0);
            zero_flag       : out STD_LOGIC;
            carry_flag      : out STD_LOGIC;
            negative_flag   : out STD_LOGIC;
            branch_taken    : out STD_LOGIC
        );
    end component;

    component Memory_Stage is
        port (
            clk             : in  STD_LOGIC;
            rst             : in  STD_LOGIC;
            alu_result_in   : in  STD_LOGIC_VECTOR(31 downto 0);
            rd2             : in  STD_LOGIC_VECTOR(31 downto 0);
            pc_in           : in  STD_LOGIC_VECTOR(31 downto 0);
            flags_in        : in  STD_LOGIC_VECTOR(31 downto 0);
            mem_read        : in  STD_LOGIC;
            mem_write       : in  STD_LOGIC;
            is_push         : in  STD_LOGIC;
            is_pushf        : in  STD_LOGIC;
            is_pop          : in  STD_LOGIC;
            is_call         : in  STD_LOGIC;
            is_ret          : in  STD_LOGIC;
            is_int          : in  STD_LOGIC;
            is_rti          : in  STD_LOGIC;
            is_jmp_int      : in  STD_LOGIC;
            int_idx         : in  STD_LOGIC;
            mem_data_out    : out STD_LOGIC_VECTOR(31 downto 0);
            alu_result_out  : out STD_LOGIC_VECTOR(31 downto 0)
        );
    end component;

    component WritebackStage is
        port (
            alu_result      : in  STD_LOGIC_VECTOR(31 downto 0);
            mem_data        : in  STD_LOGIC_VECTOR(31 downto 0);
            in_port         : in  STD_LOGIC_VECTOR(31 downto 0);
            mem_to_reg      : in  STD_LOGIC;
            alu_to_reg      : in  STD_LOGIC;
            in_port_to_reg  : in  STD_LOGIC;
            write_data      : out STD_LOGIC_VECTOR(31 downto 0)
        );
    end component;

    -- =========================================================================
    -- IF STAGE SIGNALS
    -- =========================================================================
    signal if_pc_current        : STD_LOGIC_VECTOR(31 downto 0);
    signal if_pc_plus_one       : STD_LOGIC_VECTOR(31 downto 0);
    signal if_instruction       : STD_LOGIC_VECTOR(31 downto 0);
    signal if_instr_valid       : STD_LOGIC;
    signal if_mem_address       : STD_LOGIC_VECTOR(17 downto 0);
    signal if_mem_read          : STD_LOGIC;

    -- =========================================================================
    -- IF/ID PIPELINE REGISTER
    -- =========================================================================
    signal ifid_pc              : STD_LOGIC_VECTOR(31 downto 0);
    signal ifid_pc_plus_one     : STD_LOGIC_VECTOR(31 downto 0);
    signal ifid_instruction     : STD_LOGIC_VECTOR(31 downto 0);
    signal ifid_valid           : STD_LOGIC;

    -- =========================================================================
    -- ID STAGE SIGNALS
    -- =========================================================================
    signal id_read_data1        : STD_LOGIC_VECTOR(31 downto 0);
    signal id_read_data2        : STD_LOGIC_VECTOR(31 downto 0);
    signal id_imm_ext           : STD_LOGIC_VECTOR(31 downto 0);
    signal id_alu_op            : STD_LOGIC_VECTOR(3 downto 0);
    signal id_reg_write         : STD_LOGIC;
    signal id_ccr_write         : STD_LOGIC;
    signal id_mem_read          : STD_LOGIC;
    signal id_mem_write         : STD_LOGIC;
    signal id_mem_addr_inc      : STD_LOGIC;
    signal id_is_pushf          : STD_LOGIC;
    signal id_is_call           : STD_LOGIC;
    signal id_is_ret            : STD_LOGIC;
    signal id_is_int            : STD_LOGIC;
    signal id_is_rti            : STD_LOGIC;
    signal id_is_jmp_int        : STD_LOGIC;
    signal id_use_sp            : STD_LOGIC;
    signal id_pc_write          : STD_LOGIC;
    signal id_ifid_flush        : STD_LOGIC;
    signal id_pc_mux_sel        : STD_LOGIC_VECTOR(1 downto 0);
    signal id_inject_opcode     : STD_LOGIC_VECTOR(4 downto 0);
    signal id_io_in             : STD_LOGIC;
    signal id_io_out            : STD_LOGIC;
    signal id_halt              : STD_LOGIC;
    signal id_rdst              : STD_LOGIC_VECTOR(2 downto 0);

    -- =========================================================================
    -- ID/EX PIPELINE REGISTER
    -- =========================================================================
    signal idex_pc              : STD_LOGIC_VECTOR(31 downto 0);
    signal idex_pc_plus_one     : STD_LOGIC_VECTOR(31 downto 0);
    signal idex_read_data1      : STD_LOGIC_VECTOR(31 downto 0);
    signal idex_read_data2      : STD_LOGIC_VECTOR(31 downto 0);
    signal idex_imm_ext         : STD_LOGIC_VECTOR(31 downto 0);
    signal idex_rdst            : STD_LOGIC_VECTOR(2 downto 0);
    signal idex_alu_op          : STD_LOGIC_VECTOR(3 downto 0);
    signal idex_reg_write       : STD_LOGIC;
    signal idex_ccr_write       : STD_LOGIC;
    signal idex_mem_read        : STD_LOGIC;
    signal idex_mem_write       : STD_LOGIC;
    signal idex_is_pushf        : STD_LOGIC;
    signal idex_is_call         : STD_LOGIC;
    signal idex_is_ret          : STD_LOGIC;
    signal idex_is_int          : STD_LOGIC;
    signal idex_is_rti          : STD_LOGIC;
    signal idex_is_jmp_int      : STD_LOGIC;
    signal idex_io_in           : STD_LOGIC;
    signal idex_io_out          : STD_LOGIC;

    -- =========================================================================
    -- EX STAGE SIGNALS
    -- =========================================================================
    signal ex_alu_result        : STD_LOGIC_VECTOR(31 downto 0);
    signal ex_zero_flag         : STD_LOGIC;
    signal ex_carry_flag        : STD_LOGIC;
    signal ex_negative_flag     : STD_LOGIC;
    signal ex_branch_taken      : STD_LOGIC;

    -- =========================================================================
    -- EX/MEM PIPELINE REGISTER
    -- =========================================================================
    signal exmem_pc_plus_one    : STD_LOGIC_VECTOR(31 downto 0);
    signal exmem_alu_result     : STD_LOGIC_VECTOR(31 downto 0);
    signal exmem_read_data2     : STD_LOGIC_VECTOR(31 downto 0);
    signal exmem_rdst           : STD_LOGIC_VECTOR(2 downto 0);
    signal exmem_flags          : STD_LOGIC_VECTOR(31 downto 0);
    signal exmem_reg_write      : STD_LOGIC;
    signal exmem_mem_read       : STD_LOGIC;
    signal exmem_mem_write      : STD_LOGIC;
    signal exmem_is_pushf       : STD_LOGIC;
    signal exmem_is_call        : STD_LOGIC;
    signal exmem_is_ret         : STD_LOGIC;
    signal exmem_is_int         : STD_LOGIC;
    signal exmem_is_rti         : STD_LOGIC;
    signal exmem_is_jmp_int     : STD_LOGIC;
    signal exmem_io_in          : STD_LOGIC;
    signal exmem_io_out         : STD_LOGIC;

    -- =========================================================================
    -- MEM STAGE SIGNALS
    -- =========================================================================
    signal mem_data_out         : STD_LOGIC_VECTOR(31 downto 0);
    signal mem_alu_result_out   : STD_LOGIC_VECTOR(31 downto 0);

    -- =========================================================================
    -- MEM/WB PIPELINE REGISTER
    -- =========================================================================
    signal memwb_alu_result     : STD_LOGIC_VECTOR(31 downto 0);
    signal memwb_mem_data       : STD_LOGIC_VECTOR(31 downto 0);
    signal memwb_rdst           : STD_LOGIC_VECTOR(2 downto 0);
    signal memwb_reg_write      : STD_LOGIC;
    signal memwb_mem_read       : STD_LOGIC;
    signal memwb_io_in          : STD_LOGIC;

    -- =========================================================================
    -- WB STAGE SIGNALS
    -- =========================================================================
    signal wb_write_data        : STD_LOGIC_VECTOR(31 downto 0);

    -- =========================================================================
    -- HAZARD/FORWARDING SIGNALS
    -- =========================================================================
    signal stall                : STD_LOGIC := '0';
    signal flush_ifid           : STD_LOGIC := '0';
    signal flush_idex           : STD_LOGIC := '0';
    signal forwarding_a_sel     : STD_LOGIC_VECTOR(1 downto 0) := "00";
    signal forwarding_b_sel     : STD_LOGIC_VECTOR(1 downto 0) := "00";

    -- =========================================================================
    -- MISC SIGNALS
    -- =========================================================================
    signal instr_mem_data       : STD_LOGIC_VECTOR(31 downto 0) := (others => '0');
    signal force_instr_en       : STD_LOGIC := '0';
    signal force_instr          : STD_LOGIC_VECTOR(31 downto 0) := (others => '0');
    signal out_port_reg         : STD_LOGIC_VECTOR(31 downto 0) := (others => '0');

begin

    -- =========================================================================
    -- FETCH STAGE
    -- =========================================================================
    FETCH: Fetch_Stage port map (
        clk                 => clk,
        rst                 => rst,
        reti_pc_sel         => '0',                     -- TODO: Connect from MEM/WB
        reti_pc_value       => (others => '0'),         -- TODO: Connect from MEM/WB
        branch_taken        => ex_branch_taken,
        branch_target       => ex_alu_result,           -- TODO: Proper branch target
        jump_req            => '0',                     -- TODO: Connect from ID
        jump_target         => (others => '0'),         -- TODO: Connect from ID
        stall               => stall,
        pc_write_enable     => id_pc_write,
        force_instr_en      => force_instr_en,
        force_instr         => force_instr,
        merge_upper_half    => (others => '0'),         -- TODO: For LDM
        merge_enable        => '0',
        flush_fetch         => id_ifid_flush,
        instr_mem_data      => instr_mem_data,          -- TODO: Connect to instruction memory
        mem_address         => if_mem_address,
        mem_read            => if_mem_read,
        pc_current          => if_pc_current,
        pc_plus_one_out     => if_pc_plus_one,
        instruction_out     => if_instruction,
        instruction_valid   => if_instr_valid
    );

    -- =========================================================================
    -- IF/ID PIPELINE REGISTER
    -- =========================================================================
    process(clk, rst)
    begin
        if rst = '1' then
            ifid_pc          <= (others => '0');
            ifid_pc_plus_one <= (others => '0');
            ifid_instruction <= (others => '0');
            ifid_valid       <= '0';
        elsif rising_edge(clk) then
            if stall = '0' then
                if flush_ifid = '1' or id_ifid_flush = '1' then
                    ifid_instruction <= (others => '0');  -- NOP
                    ifid_valid       <= '0';
                else
                    ifid_pc          <= if_pc_current;
                    ifid_pc_plus_one <= if_pc_plus_one;
                    ifid_instruction <= if_instruction;
                    ifid_valid       <= if_instr_valid;
                end if;
            end if;
        end if;
    end process;

    -- =========================================================================
    -- DECODE STAGE
    -- =========================================================================
    id_rdst <= ifid_instruction(26 downto 24);

    DECODE: DecodeStage port map (
        clk             => clk,
        rst             => rst,
        instr           => ifid_instruction,
        write_data      => wb_write_data,
        write_reg_addr  => memwb_rdst,
        reg_write_en    => memwb_reg_write,
        read_data1      => id_read_data1,
        read_data2      => id_read_data2,
        imm_ext         => id_imm_ext,
        alu_op          => id_alu_op,
        reg_write       => id_reg_write,
        ccr_write       => id_ccr_write,
        mem_read        => id_mem_read,
        mem_write       => id_mem_write,
        mem_addr_inc    => id_mem_addr_inc,
        is_pushf        => id_is_pushf,
        is_call         => id_is_call,
        is_ret          => id_is_ret,
        is_int          => id_is_int,
        is_rti          => id_is_rti,
        is_jmp_int      => id_is_jmp_int,
        use_sp          => id_use_sp,
        pc_write        => id_pc_write,
        ifid_flush      => id_ifid_flush,
        pc_mux_sel      => id_pc_mux_sel,
        inject_opcode   => id_inject_opcode,
        io_in           => id_io_in,
        io_out          => id_io_out,
        halt            => id_halt
    );

    -- =========================================================================
    -- ID/EX PIPELINE REGISTER
    -- =========================================================================
    process(clk, rst)
    begin
        if rst = '1' then
            idex_pc          <= (others => '0');
            idex_pc_plus_one <= (others => '0');
            idex_read_data1  <= (others => '0');
            idex_read_data2  <= (others => '0');
            idex_imm_ext     <= (others => '0');
            idex_rdst        <= (others => '0');
            idex_alu_op      <= (others => '0');
            idex_reg_write   <= '0';
            idex_ccr_write   <= '0';
            idex_mem_read    <= '0';
            idex_mem_write   <= '0';
            idex_is_pushf    <= '0';
            idex_is_call     <= '0';
            idex_is_ret      <= '0';
            idex_is_int      <= '0';
            idex_is_rti      <= '0';
            idex_is_jmp_int  <= '0';
            idex_io_in       <= '0';
            idex_io_out      <= '0';
        elsif rising_edge(clk) then
            if flush_idex = '1' then
                -- Insert bubble (NOP)
                idex_alu_op      <= (others => '0');
                idex_reg_write   <= '0';
                idex_ccr_write   <= '0';
                idex_mem_read    <= '0';
                idex_mem_write   <= '0';
                idex_is_pushf    <= '0';
                idex_is_call     <= '0';
                idex_is_ret      <= '0';
                idex_is_int      <= '0';
                idex_is_rti      <= '0';
                idex_is_jmp_int  <= '0';
                idex_io_in       <= '0';
                idex_io_out      <= '0';
            elsif stall = '0' then
                idex_pc          <= ifid_pc;
                idex_pc_plus_one <= ifid_pc_plus_one;
                idex_read_data1  <= id_read_data1;
                idex_read_data2  <= id_read_data2;
                idex_imm_ext     <= id_imm_ext;
                idex_rdst        <= id_rdst;
                idex_alu_op      <= id_alu_op;
                idex_reg_write   <= id_reg_write;
                idex_ccr_write   <= id_ccr_write;
                idex_mem_read    <= id_mem_read;
                idex_mem_write   <= id_mem_write;
                idex_is_pushf    <= id_is_pushf;
                idex_is_call     <= id_is_call;
                idex_is_ret      <= id_is_ret;
                idex_is_int      <= id_is_int;
                idex_is_rti      <= id_is_rti;
                idex_is_jmp_int  <= id_is_jmp_int;
                idex_io_in       <= id_io_in;
                idex_io_out      <= id_io_out;
            end if;
        end if;
    end process;

    -- =========================================================================
    -- EXECUTE STAGE
    -- =========================================================================
    EXECUTE: ExecuteStage 
        generic map (
            DATA_WIDTH => 32
        )
        port map (
            clk             => clk,
            rst             => rst,
            jz              => '0',                     -- TODO: From control
            jn              => '0',                     -- TODO: From control
            jc              => '0',                     -- TODO: From control
            alu_op          => idex_alu_op,             -- TODO: Convert to alu_op_t
            operand_a       => idex_read_data1,
            operand_b       => idex_read_data2,
            immediate_value => idex_imm_ext,
            use_immediate   => '0',                     -- TODO: From control
            wb_value        => wb_write_data,
            mem_value       => mem_alu_result_out,
            forwarding_a_sel=> forwarding_a_sel,
            forwarding_b_sel=> forwarding_b_sel,
            flags_we        => '0',                     -- TODO: For RTI
            flags_data      => (others => '0'),
            alu_out         => ex_alu_result,
            zero_flag       => ex_zero_flag,
            carry_flag      => ex_carry_flag,
            negative_flag   => ex_negative_flag,
            branch_taken    => ex_branch_taken
        );

    -- =========================================================================
    -- EX/MEM PIPELINE REGISTER
    -- =========================================================================
    process(clk, rst)
    begin
        if rst = '1' then
            exmem_pc_plus_one <= (others => '0');
            exmem_alu_result  <= (others => '0');
            exmem_read_data2  <= (others => '0');
            exmem_rdst        <= (others => '0');
            exmem_flags       <= (others => '0');
            exmem_reg_write   <= '0';
            exmem_mem_read    <= '0';
            exmem_mem_write   <= '0';
            exmem_is_pushf    <= '0';
            exmem_is_call     <= '0';
            exmem_is_ret      <= '0';
            exmem_is_int      <= '0';
            exmem_is_rti      <= '0';
            exmem_is_jmp_int  <= '0';
            exmem_io_in       <= '0';
            exmem_io_out      <= '0';
        elsif rising_edge(clk) then
            exmem_pc_plus_one <= idex_pc_plus_one;
            exmem_alu_result  <= ex_alu_result;
            exmem_read_data2  <= idex_read_data2;
            exmem_rdst        <= idex_rdst;
            exmem_flags       <= (others => '0');       -- TODO: Actual flags
            exmem_flags(0)    <= ex_zero_flag;
            exmem_flags(1)    <= ex_carry_flag;
            exmem_flags(2)    <= ex_negative_flag;
            exmem_reg_write   <= idex_reg_write;
            exmem_mem_read    <= idex_mem_read;
            exmem_mem_write   <= idex_mem_write;
            exmem_is_pushf    <= idex_is_pushf;
            exmem_is_call     <= idex_is_call;
            exmem_is_ret      <= idex_is_ret;
            exmem_is_int      <= idex_is_int;
            exmem_is_rti      <= idex_is_rti;
            exmem_is_jmp_int  <= idex_is_jmp_int;
            exmem_io_in       <= idex_io_in;
            exmem_io_out      <= idex_io_out;
        end if;
    end process;

    -- =========================================================================
    -- MEMORY STAGE
    -- =========================================================================
    MEMORY: Memory_Stage port map (
        clk             => clk,
        rst             => rst,
        alu_result_in   => exmem_alu_result,
        rd2             => exmem_read_data2,
        pc_in           => exmem_pc_plus_one,
        flags_in        => exmem_flags,
        mem_read        => exmem_mem_read,
        mem_write       => exmem_mem_write,
        is_push         => '0',                         -- TODO: Add signal
        is_pushf        => exmem_is_pushf,
        is_pop          => '0',                         -- TODO: Add signal
        is_call         => exmem_is_call,
        is_ret          => exmem_is_ret,
        is_int          => exmem_is_int,
        is_rti          => exmem_is_rti,
        is_jmp_int      => exmem_is_jmp_int,
        int_idx         => '0',                         -- TODO: From instruction
        mem_data_out    => mem_data_out,
        alu_result_out  => mem_alu_result_out
    );

    -- =========================================================================
    -- MEM/WB PIPELINE REGISTER
    -- =========================================================================
    process(clk, rst)
    begin
        if rst = '1' then
            memwb_alu_result <= (others => '0');
            memwb_mem_data   <= (others => '0');
            memwb_rdst       <= (others => '0');
            memwb_reg_write  <= '0';
            memwb_mem_read   <= '0';
            memwb_io_in      <= '0';
        elsif rising_edge(clk) then
            memwb_alu_result <= mem_alu_result_out;
            memwb_mem_data   <= mem_data_out;
            memwb_rdst       <= exmem_rdst;
            memwb_reg_write  <= exmem_reg_write;
            memwb_mem_read   <= exmem_mem_read;
            memwb_io_in      <= exmem_io_in;
        end if;
    end process;

    -- =========================================================================
    -- WRITEBACK STAGE
    -- =========================================================================
    WRITEBACK: WritebackStage port map (
        alu_result      => memwb_alu_result,
        mem_data        => memwb_mem_data,
        in_port         => in_port,
        mem_to_reg      => memwb_mem_read,
        alu_to_reg      => not memwb_mem_read and not memwb_io_in,
        in_port_to_reg  => memwb_io_in,
        write_data      => wb_write_data
    );

    -- =========================================================================
    -- OUTPUT PORT
    -- =========================================================================
    process(clk, rst)
    begin
        if rst = '1' then
            out_port_reg <= (others => '0');
        elsif rising_edge(clk) then
            if exmem_io_out = '1' then
                out_port_reg <= exmem_read_data2;
            end if;
        end if;
    end process;

    out_port <= out_port_reg;

    -- =========================================================================
    -- TODO: HAZARD DETECTION UNIT
    -- =========================================================================
    -- stall <= ...
    -- flush_ifid <= ...
    -- flush_idex <= ...

    -- =========================================================================
    -- TODO: FORWARDING UNIT
    -- =========================================================================
    -- forwarding_a_sel <= ...
    -- forwarding_b_sel <= ...

    -- =========================================================================
    -- TODO: INSTRUCTION INJECTION (for INT/RTI micro-ops)
    -- =========================================================================
    -- force_instr_en <= '1' when id_inject_opcode /= "00000" else '0';
    -- force_instr <= id_inject_opcode & "000" & x"00" & x"0000";

end Behavioral;

examples.after_code:
LIBRARY IEEE;
USE IEEE.STD_LOGIC_1164.ALL;
USE IEEE.NUMERIC_STD.ALL;

ENTITY Processor IS
    PORT (
        clk : IN std_logic;
        rst : IN std_logic;
        in_port : IN std_logic_vector(31 DOWNTO 0);
        out_port : OUT std_logic_vector(31 DOWNTO 0)
    );
END Processor;

ARCHITECTURE Behavioral OF Processor IS

    -- =========================================================================
    -- COMPONENT DECLARATIONS
    -- =========================================================================

    COMPONENT Fetch_Stage IS
        PORT (
            clk : IN std_logic;
            rst : IN std_logic;
            reti_pc_sel : IN std_logic;
            reti_pc_value : IN std_logic_vector(31 DOWNTO 0);
            branch_taken : IN std_logic;
            branch_target : IN std_logic_vector(31 DOWNTO 0);
            jump_req : IN std_logic;
            jump_target : IN std_logic_vector(31 DOWNTO 0);
            stall : IN std_logic;
            pc_write_enable : IN std_logic;
            force_instr_en : IN std_logic;
            force_instr : IN std_logic_vector(31 DOWNTO 0);
            merge_upper_half : IN std_logic_vector(15 DOWNTO 0);
            merge_enable : IN std_logic;
            flush_fetch : IN std_logic;
            instr_mem_data : IN std_logic_vector(31 DOWNTO 0);
            mem_address : OUT std_logic_vector(17 DOWNTO 0);
            mem_read : OUT std_logic;
            pc_current : OUT std_logic_vector(31 DOWNTO 0);
            pc_plus_one_out : OUT std_logic_vector(31 DOWNTO 0);
            instruction_out : OUT std_logic_vector(31 DOWNTO 0);
            instruction_valid : OUT std_logic
        );
    END COMPONENT;

    COMPONENT DecodeStage IS
        PORT (
            clk : IN std_logic;
            rst : IN std_logic;
            instr : IN std_logic_vector(31 DOWNTO 0);
            write_data : IN std_logic_vector(31 DOWNTO 0);
            write_reg_addr : IN std_logic_vector(2 DOWNTO 0);
            reg_write_en : IN std_logic;
            read_data1 : OUT std_logic_vector(31 DOWNTO 0);
            read_data2 : OUT std_logic_vector(31 DOWNTO 0);
            imm_ext : OUT std_logic_vector(31 DOWNTO 0);
            alu_op : OUT std_logic_vector(3 DOWNTO 0);
            reg_write : OUT std_logic;
            ccr_write : OUT std_logic;
            mem_read : OUT std_logic;
            mem_write : OUT std_logic;
            mem_addr_inc : OUT std_logic;
            is_pushf : OUT std_logic;
            is_call : OUT std_logic;
            is_ret : OUT std_logic;
            is_int : OUT std_logic;
            is_rti : OUT std_logic;
            is_jmp_int : OUT std_logic;
            use_sp : OUT std_logic;
            is_jz : OUT std_logic;
            is_jn : OUT std_logic;
            is_jc : OUT std_logic;
            is_jmp : OUT std_logic;
            pc_write : OUT std_logic;
            ifid_flush : OUT std_logic;
            pc_mux_sel : OUT std_logic_vector(1 DOWNTO 0);
            inject_opcode : OUT std_logic_vector(4 DOWNTO 0);
            io_in : OUT std_logic;
            io_out : OUT std_logic;
            halt : OUT std_logic
        );
    END COMPONENT;

    COMPONENT ExecuteStage IS
        GENERIC (
            DATA_WIDTH : integer := 32
        );
        PORT (
            clk : IN std_logic;
            rst : IN std_logic;
            jz : IN std_logic;
            jn : IN std_logic;
            jc : IN std_logic;
            alu_op : IN std_logic_vector(3 DOWNTO 0);
            operand_a : IN std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
            operand_b : IN std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
            immediate_value : IN std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
            use_immediate : IN std_logic;
            wb_value : IN std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
            mem_value : IN std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
            forwarding_a_sel : IN std_logic_vector(1 DOWNTO 0);
            forwarding_b_sel : IN std_logic_vector(1 DOWNTO 0);
            flags_we : IN std_logic;
            flags_data : IN std_logic_vector(2 DOWNTO 0);
            alu_out : OUT std_logic_vector(DATA_WIDTH - 1 DOWNTO 0);
            zero_flag : OUT std_logic;
            carry_flag : OUT std_logic;
            negative_flag : OUT std_logic;
            branch_taken : OUT std_logic
        );
    END COMPONENT;

    COMPONENT Memory_Stage IS
        PORT (
            clk : IN std_logic;
            rst : IN std_logic;
            alu_result_in : IN std_logic_vector(31 DOWNTO 0);
            rd2 : IN std_logic_vector(31 DOWNTO 0);
            pc_in : IN std_logic_vector(31 DOWNTO 0);
            flags_in : IN std_logic_vector(31 DOWNTO 0);
            mem_read : IN std_logic;
            mem_write : IN std_logic;
            is_push : IN std_logic;
            is_pushf : IN std_logic;
            is_pop : IN std_logic;
            is_call : IN std_logic;
            is_ret : IN std_logic;
            is_int : IN std_logic;
            is_rti : IN std_logic;
            is_jmp_int : IN std_logic;
            int_idx : IN std_logic;
            mem_data_out : OUT std_logic_vector(31 DOWNTO 0);
            alu_result_out : OUT std_logic_vector(31 DOWNTO 0)
        );
    END COMPONENT;

    COMPONENT WritebackStage IS
        PORT (
            alu_result : IN std_logic_vector(31 DOWNTO 0);
            mem_data : IN std_logic_vector(31 DOWNTO 0);
            in_port : IN std_logic_vector(31 DOWNTO 0);
            mem_to_reg : IN std_logic;
            alu_to_reg : IN std_logic;
            in_port_to_reg : IN std_logic;
            write_data : OUT std_logic_vector(31 DOWNTO 0)
        );
    END COMPONENT;

    -- =========================================================================
    -- IF STAGE SIGNALS
    -- =========================================================================
    SIGNAL if_pc_current : std_logic_vector(31 DOWNTO 0);
    SIGNAL if_pc_plus_one : std_logic_vector(31 DOWNTO 0);
    SIGNAL if_instruction : std_logic_vector(31 DOWNTO 0);
    SIGNAL if_instr_valid : std_logic;
    SIGNAL if_mem_address : std_logic_vector(17 DOWNTO 0);
    SIGNAL if_mem_read : std_logic;

    -- =========================================================================
    -- IF/ID PIPELINE REGISTER
    -- =========================================================================
    SIGNAL ifid_pc : std_logic_vector(31 DOWNTO 0);
    SIGNAL ifid_pc_plus_one : std_logic_vector(31 DOWNTO 0);
    SIGNAL ifid_instruction : std_logic_vector(31 DOWNTO 0);
    SIGNAL ifid_valid : std_logic;

    -- =========================================================================
    -- ID STAGE SIGNALS
    -- =========================================================================
    SIGNAL id_read_data1 : std_logic_vector(31 DOWNTO 0);
    SIGNAL id_read_data2 : std_logic_vector(31 DOWNTO 0);
    SIGNAL id_imm_ext : std_logic_vector(31 DOWNTO 0);
    SIGNAL id_alu_op : std_logic_vector(3 DOWNTO 0);
    SIGNAL id_reg_write : std_logic;
    SIGNAL id_ccr_write : std_logic;
    SIGNAL id_mem_read : std_logic;
    SIGNAL id_mem_write : std_logic;
    SIGNAL id_mem_addr_inc : std_logic;
    SIGNAL id_is_pushf : std_logic;
    SIGNAL id_is_call : std_logic;
    SIGNAL id_is_ret : std_logic;
    SIGNAL id_is_int : std_logic;
    SIGNAL id_is_rti : std_logic;
    SIGNAL id_is_jmp_int : std_logic;
    SIGNAL id_use_sp : std_logic;
    SIGNAL id_is_jz : std_logic;
    SIGNAL id_is_jn : std_logic;
    SIGNAL id_is_jc : std_logic;
    SIGNAL id_is_jmp : std_logic;
    SIGNAL id_pc_write : std_logic;
    SIGNAL id_ifid_flush : std_logic;
    SIGNAL id_pc_mux_sel : std_logic_vector(1 DOWNTO 0);
    SIGNAL id_inject_opcode : std_logic_vector(4 DOWNTO 0);
    SIGNAL id_io_in : std_logic;
    SIGNAL id_io_out : std_logic;
    SIGNAL id_halt : std_logic;
    SIGNAL id_rdst : std_logic_vector(2 DOWNTO 0);

    -- =========================================================================
    -- ID/EX PIPELINE REGISTER
    -- =========================================================================
    SIGNAL idex_pc : std_logic_vector(31 DOWNTO 0);
    SIGNAL idex_pc_plus_one : std_logic_vector(31 DOWNTO 0);
    SIGNAL idex_read_data1 : std_logic_vector(31 DOWNTO 0);
    SIGNAL idex_read_data2 : std_logic_vector(31 DOWNTO 0);
    SIGNAL idex_imm_ext : std_logic_vector(31 DOWNTO 0);
    SIGNAL idex_rdst : std_logic_vector(2 DOWNTO 0);
    SIGNAL idex_alu_op : std_logic_vector(3 DOWNTO 0);
    SIGNAL idex_reg_write : std_logic;
    SIGNAL idex_ccr_write : std_logic;
    SIGNAL idex_mem_read : std_logic;
    SIGNAL idex_mem_write : std_logic;
    SIGNAL idex_is_pushf : std_logic;
    SIGNAL idex_is_call : std_logic;
    SIGNAL idex_is_ret : std_logic;
    SIGNAL idex_is_int : std_logic;
    SIGNAL idex_is_rti : std_logic;
    SIGNAL idex_is_jmp_int : std_logic;
    SIGNAL idex_is_jz : std_logic;
    SIGNAL idex_is_jn : std_logic;
    SIGNAL idex_is_jc : std_logic;
    SIGNAL idex_io_in : std_logic;
    SIGNAL idex_io_out : std_logic;

    -- =========================================================================
    -- EX STAGE SIGNALS
    -- =========================================================================
    SIGNAL ex_alu_result : std_logic_vector(31 DOWNTO 0);
    SIGNAL ex_zero_flag : std_logic;
    SIGNAL ex_carry_flag : std_logic;
    SIGNAL ex_negative_flag : std_logic;
    SIGNAL ex_branch_taken : std_logic;
    SIGNAL fetch_flush : std_logic;

    -- =========================================================================
    -- EX/MEM PIPELINE REGISTER
    -- =========================================================================
    SIGNAL exmem_pc_plus_one : std_logic_vector(31 DOWNTO 0);
    SIGNAL exmem_alu_result : std_logic_vector(31 DOWNTO 0);
    SIGNAL exmem_read_data2 : std_logic_vector(31 DOWNTO 0);
    SIGNAL exmem_rdst : std_logic_vector(2 DOWNTO 0);
    SIGNAL exmem_flags : std_logic_vector(31 DOWNTO 0);
    SIGNAL exmem_reg_write : std_logic;
    SIGNAL exmem_mem_read : std_logic;
    SIGNAL exmem_mem_write : std_logic;
    SIGNAL exmem_is_pushf : std_logic;
    SIGNAL exmem_is_call : std_logic;
    SIGNAL exmem_is_ret : std_logic;
    SIGNAL exmem_is_int : std_logic;
    SIGNAL exmem_is_rti : std_logic;
    SIGNAL exmem_is_jmp_int : std_logic;
    SIGNAL exmem_io_in : std_logic;
    SIGNAL exmem_io_out : std_logic;

    -- =========================================================================
    -- MEM STAGE SIGNALS
    -- =========================================================================
    SIGNAL mem_data_out : std_logic_vector(31 DOWNTO 0);
    SIGNAL mem_alu_result_out : std_logic_vector(31 DOWNTO 0);

    -- =========================================================================
    -- MEM/WB PIPELINE REGISTER
    -- =========================================================================
    SIGNAL memwb_alu_result : std_logic_vector(31 DOWNTO 0);
    SIGNAL memwb_mem_data : std_logic_vector(31 DOWNTO 0);
    SIGNAL memwb_rdst : std_logic_vector(2 DOWNTO 0);
    SIGNAL memwb_reg_write : std_logic;
    SIGNAL memwb_mem_read : std_logic;
    SIGNAL memwb_io_in : std_logic;

    -- =========================================================================
    -- WB STAGE SIGNALS
    -- =========================================================================
    SIGNAL wb_write_data : std_logic_vector(31 DOWNTO 0);
    SIGNAL wb_alu_to_reg : std_logic;

    -- =========================================================================
    -- HAZARD/FORWARDING SIGNALS
    -- =========================================================================
    SIGNAL stall : std_logic := '0';
    SIGNAL flush_ifid : std_logic := '0';
    SIGNAL flush_idex : std_logic := '0';
    SIGNAL forwarding_a_sel : std_logic_vector(1 DOWNTO 0) := "00";
    SIGNAL forwarding_b_sel : std_logic_vector(1 DOWNTO 0) := "00";

    -- =========================================================================
    -- MISC SIGNALS
    -- =========================================================================
    SIGNAL instr_mem_data : std_logic_vector(31 DOWNTO 0) := (OTHERS => '0');
    SIGNAL force_instr_en : std_logic := '0';
    SIGNAL force_instr : std_logic_vector(31 DOWNTO 0) := (OTHERS => '0');
    SIGNAL out_port_reg : std_logic_vector(31 DOWNTO 0) := (OTHERS => '0');

BEGIN

    fetch_flush <= id_ifid_flush OR ex_branch_taken;
    wb_alu_to_reg <= NOT memwb_mem_read AND NOT memwb_io_in;

    -- =========================================================================
    -- FETCH STAGE
    -- =========================================================================
    FETCH : Fetch_Stage PORT MAP(
        clk => clk,
        rst => rst,
        reti_pc_sel => '0', -- TODO: Connect from MEM/WB
        reti_pc_value => (OTHERS => '0'), -- TODO: Connect from MEM/WB
        branch_taken => ex_branch_taken,
        branch_target => idex_imm_ext,
        jump_req => id_is_jmp,
        jump_target => id_imm_ext,
        stall => stall,
        pc_write_enable => id_pc_write,
        force_instr_en => force_instr_en,
        force_instr => force_instr,
        merge_upper_half => (OTHERS => '0'), -- TODO: For LDM
        merge_enable => '0',
        flush_fetch => fetch_flush, -- Flush on JMP or conditional branch taken
        instr_mem_data => instr_mem_data, -- TODO: Connect to instruction memory
        mem_address => if_mem_address,
        mem_read => if_mem_read,
        pc_current => if_pc_current,
        pc_plus_one_out => if_pc_plus_one,
        instruction_out => if_instruction,
        instruction_valid => if_instr_valid
    );

    -- =========================================================================
    -- IF/ID PIPELINE REGISTER
    -- =========================================================================
    PROCESS (clk, rst)
    BEGIN
        IF rst = '1' THEN
            ifid_pc <= (OTHERS => '0');
            ifid_pc_plus_one <= (OTHERS => '0');
            ifid_instruction <= (OTHERS => '0');
            ifid_valid <= '0';
        ELSIF rising_edge(clk) THEN
            IF stall = '0' THEN
                IF flush_ifid = '1' OR id_ifid_flush = '1' THEN
                    ifid_instruction <= (OTHERS => '0'); -- NOP
                    ifid_valid <= '0';
                ELSE
                    ifid_pc <= if_pc_current;
                    ifid_pc_plus_one <= if_pc_plus_one;
                    ifid_instruction <= if_instruction;
                    ifid_valid <= if_instr_valid;
                END IF;
            END IF;
        END IF;
    END PROCESS;

    -- =========================================================================
    -- DECODE STAGE
    -- =========================================================================
    id_rdst <= ifid_instruction(26 DOWNTO 24);

    DECODE : DecodeStage PORT MAP(
        clk => clk,
        rst => rst,
        instr => ifid_instruction,
        write_data => wb_write_data,
        write_reg_addr => memwb_rdst,
        reg_write_en => memwb_reg_write,
        read_data1 => id_read_data1,
        read_data2 => id_read_data2,
        imm_ext => id_imm_ext,
        alu_op => id_alu_op,
        reg_write => id_reg_write,
        ccr_write => id_ccr_write,
        mem_read => id_mem_read,
        mem_write => id_mem_write,
        mem_addr_inc => id_mem_addr_inc,
        is_pushf => id_is_pushf,
        is_call => id_is_call,
        is_ret => id_is_ret,
        is_int => id_is_int,
        is_rti => id_is_rti,
        is_jmp_int => id_is_jmp_int,
        use_sp => id_use_sp,
        is_jz => id_is_jz,
        is_jn => id_is_jn,
        is_jc => id_is_jc,
        is_jmp => id_is_jmp,
        pc_write => id_pc_write,
        ifid_flush => id_ifid_flush,
        pc_mux_sel => id_pc_mux_sel,
        inject_opcode => id_inject_opcode,
        io_in => id_io_in,
        io_out => id_io_out,
        halt => id_halt
    );

    -- =========================================================================
    -- ID/EX PIPELINE REGISTER
    -- =========================================================================
    PROCESS (clk, rst)
    BEGIN
        IF rst = '1' THEN
            idex_pc <= (OTHERS => '0');
            idex_pc_plus_one <= (OTHERS => '0');
            idex_read_data1 <= (OTHERS => '0');
            idex_read_data2 <= (OTHERS => '0');
            idex_imm_ext <= (OTHERS => '0');
            idex_rdst <= (OTHERS => '0');
            idex_alu_op <= (OTHERS => '0');
            idex_reg_write <= '0';
            idex_ccr_write <= '0';
            idex_mem_read <= '0';
            idex_mem_write <= '0';
            idex_is_pushf <= '0';
            idex_is_call <= '0';
            idex_is_ret <= '0';
            idex_is_int <= '0';
            idex_is_rti <= '0';
            idex_is_jmp_int <= '0';
            idex_is_jz <= '0';
            idex_is_jn <= '0';
            idex_is_jc <= '0';
            idex_io_in <= '0';
            idex_io_out <= '0';
        ELSIF rising_edge(clk) THEN
            IF flush_idex = '1' THEN
                -- Insert bubble (NOP)
                idex_alu_op <= (OTHERS => '0');
                idex_reg_write <= '0';
                idex_ccr_write <= '0';
                idex_mem_read <= '0';
                idex_mem_write <= '0';
                idex_is_pushf <= '0';
                idex_is_call <= '0';
                idex_is_ret <= '0';
                idex_is_int <= '0';
                idex_is_rti <= '0';
                idex_is_jmp_int <= '0';
                idex_is_jz <= '0';
                idex_is_jn <= '0';
                idex_is_jc <= '0';
                idex_io_in <= '0';
                idex_io_out <= '0';
            ELSIF stall = '0' THEN
                idex_pc <= ifid_pc;
                idex_pc_plus_one <= ifid_pc_plus_one;
                idex_read_data1 <= id_read_data1;
                idex_read_data2 <= id_read_data2;
                idex_imm_ext <= id_imm_ext;
                idex_rdst <= id_rdst;
                idex_alu_op <= id_alu_op;
                idex_reg_write <= id_reg_write;
                idex_ccr_write <= id_ccr_write;
                idex_mem_read <= id_mem_read;
                idex_mem_write <= id_mem_write;
                idex_is_pushf <= id_is_pushf;
                idex_is_call <= id_is_call;
                idex_is_ret <= id_is_ret;
                idex_is_int <= id_is_int;
                idex_is_rti <= id_is_rti;
                idex_is_jmp_int <= id_is_jmp_int;
                idex_is_jz <= id_is_jz;
                idex_is_jn <= id_is_jn;
                idex_is_jc <= id_is_jc;
                idex_io_in <= id_io_in;
                idex_io_out <= id_io_out;
            END IF;
        END IF;
    END PROCESS;

    -- =========================================================================
    -- EXECUTE STAGE
    -- =========================================================================
    EXECUTE : ExecuteStage
    GENERIC MAP(
        DATA_WIDTH => 32
    )
    PORT MAP(
        clk => clk,
        rst => rst,
        jz => idex_is_jz,
        jn => idex_is_jn,
        jc => idex_is_jc,
        alu_op => idex_alu_op,
        operand_a => idex_read_data1,
        operand_b => idex_read_data2,
        immediate_value => idex_imm_ext,
        use_immediate => '0', -- TODO: From control
        wb_value => wb_write_data,
        mem_value => mem_alu_result_out,
        forwarding_a_sel => forwarding_a_sel,
        forwarding_b_sel => forwarding_b_sel,
        flags_we => '0', -- TODO: For RTI
        flags_data => (OTHERS => '0'),
        alu_out => ex_alu_result,
        zero_flag => ex_zero_flag,
        carry_flag => ex_carry_flag,
        negative_flag => ex_negative_flag,
        branch_taken => ex_branch_taken
    );

    -- =========================================================================
    -- EX/MEM PIPELINE REGISTER
    -- =========================================================================
    PROCESS (clk, rst)
    BEGIN
        IF rst = '1' THEN
            exmem_pc_plus_one <= (OTHERS => '0');
            exmem_alu_result <= (OTHERS => '0');
            exmem_read_data2 <= (OTHERS => '0');
            exmem_rdst <= (OTHERS => '0');
            exmem_flags <= (OTHERS => '0');
            exmem_reg_write <= '0';
            exmem_mem_read <= '0';
            exmem_mem_write <= '0';
            exmem_is_pushf <= '0';
            exmem_is_call <= '0';
            exmem_is_ret <= '0';
            exmem_is_int <= '0';
            exmem_is_rti <= '0';
            exmem_is_jmp_int <= '0';
            exmem_io_in <= '0';
            exmem_io_out <= '0';
        ELSIF rising_edge(clk) THEN
            exmem_pc_plus_one <= idex_pc_plus_one;
            exmem_alu_result <= ex_alu_result;
            exmem_read_data2 <= idex_read_data2;
            exmem_rdst <= idex_rdst;
            exmem_flags <= (OTHERS => '0'); -- TODO: Actual flags
            exmem_flags(0) <= ex_zero_flag;
            exmem_flags(1) <= ex_carry_flag;
            exmem_flags(2) <= ex_negative_flag;
            exmem_reg_write <= idex_reg_write;
            exmem_mem_read <= idex_mem_read;
            exmem_mem_write <= idex_mem_write;
            exmem_is_pushf <= idex_is_pushf;
            exmem_is_call <= idex_is_call;
            exmem_is_ret <= idex_is_ret;
            exmem_is_int <= idex_is_int;
            exmem_is_rti <= idex_is_rti;
            exmem_is_jmp_int <= idex_is_jmp_int;
            exmem_io_in <= idex_io_in;
            exmem_io_out <= idex_io_out;
        END IF;
    END PROCESS;

    -- =========================================================================
    -- MEMORY STAGE
    -- =========================================================================
    MEMORY : Memory_Stage PORT MAP(
        clk => clk,
        rst => rst,
        alu_result_in => exmem_alu_result,
        rd2 => exmem_read_data2,
        pc_in => exmem_pc_plus_one,
        flags_in => exmem_flags,
        mem_read => exmem_mem_read,
        mem_write => exmem_mem_write,
        is_push => '0', -- TODO: Add signal
        is_pushf => exmem_is_pushf,
        is_pop => '0', -- TODO: Add signal
        is_call => exmem_is_call,
        is_ret => exmem_is_ret,
        is_int => exmem_is_int,
        is_rti => exmem_is_rti,
        is_jmp_int => exmem_is_jmp_int,
        int_idx => '0', -- TODO: From instruction
        mem_data_out => mem_data_out,
        alu_result_out => mem_alu_result_out
    );

    -- =========================================================================
    -- MEM/WB PIPELINE REGISTER
    -- =========================================================================
    PROCESS (clk, rst)
    BEGIN
        IF rst = '1' THEN
            memwb_alu_result <= (OTHERS => '0');
            memwb_mem_data <= (OTHERS => '0');
            memwb_rdst <= (OTHERS => '0');
            memwb_reg_write <= '0';
            memwb_mem_read <= '0';
            memwb_io_in <= '0';
        ELSIF rising_edge(clk) THEN
            memwb_alu_result <= mem_alu_result_out;
            memwb_mem_data <= mem_data_out;
            memwb_rdst <= exmem_rdst;
            memwb_reg_write <= exmem_reg_write;
            memwb_mem_read <= exmem_mem_read;
            memwb_io_in <= exmem_io_in;
        END IF;
    END PROCESS;

    -- =========================================================================
    -- WRITEBACK STAGE
    -- =========================================================================
    WRITEBACK : WritebackStage PORT MAP(
        alu_result => memwb_alu_result,
        mem_data => memwb_mem_data,
        in_port => in_port,
        mem_to_reg => memwb_mem_read,
        alu_to_reg => wb_alu_to_reg,
        in_port_to_reg => memwb_io_in,
        write_data => wb_write_data
    );

    -- =========================================================================
    -- OUTPUT PORT
    -- =========================================================================
    PROCESS (clk, rst)
    BEGIN
        IF rst = '1' THEN
            out_port_reg <= (OTHERS => '0');
        ELSIF rising_edge(clk) THEN
            IF exmem_io_out = '1' THEN
                out_port_reg <= exmem_read_data2;
            END IF;
        END IF;
    END PROCESS;

    out_port <= out_port_reg;

    -- =========================================================================
    -- TODO: HAZARD DETECTION UNIT
    -- =========================================================================
    -- stall <= ...
